css_variables:
:root {
  --primary: #2A5A6D;
  --primary-foreground: #F8F8F8;

  --secondary: #7A9CA9;
  --secondary-foreground: #202020;

  --accent: #A04E6D;
  --accent-foreground: #F8F8F8;

  --background: #FDFDFD;
  --foreground: #202020;

  --surface: #F4F4F4;

  --muted: #DEDEDE;
  --muted-foreground: #606060;

  --border: #EAEAEA;

  --destructive: #DC2626;
  --destructive-foreground: #F8F8F8;

  --success: #22C55E;
  --warning: #FACC15;
  --info: #3B82F6;

  --radius: 8px;

  /* Typography */
  --font-sans: 'DM Sans', sans-serif;
  --font-heading: 'Urbanist', sans-serif;
  --font-mono: 'Space Mono', monospace;
}
